def gen(rng, size):
    n = max(1, min(size, 100000))
    nums = []
    for i in range(n):
        if i % 2 == 0:
            nums.append(rng.randint(50001, 100000))
        else:
            nums.append(rng.randint(1, 50000))
    k = rng.randint(1, max(1, min(5, n)))
    return [nums, k]

