class Solution:
    def maxAlternatingSum(self, nums, k):
        n = len(nums)
        inc = [0] * n
        dec = [0] * n
        best = 0
        for i in range(n):
            v = nums[i]
            best_dec_before = 0
            best_inc_before = 0
            for j in range(0, i - k + 1):
                if nums[j] < v and dec[j] > best_dec_before:
                    best_dec_before = dec[j]
                if nums[j] > v and inc[j] > best_inc_before:
                    best_inc_before = inc[j]
            inc[i] = v + best_dec_before
            dec[i] = v + best_inc_before
            if inc[i] > best:
                best = inc[i]
            if dec[i] > best:
                best = dec[i]
        return best

