class Solution:
    def maxAlternatingSum(self, nums: list[int], k: int) -> int:
        n = len(nums)
        max_v = max(nums)

        class FenwickMax:
            def __init__(self, size):
                self.n = size
                self.tree = [0] * (size + 1)

            def update(self, i, value):
                while i <= self.n:
                    if self.tree[i] < value:
                        self.tree[i] = value
                    i += i & (-i)

            def query(self, i):
                res = 0
                while i > 0:
                    if self.tree[i] > res:
                        res = self.tree[i]
                    i -= i & (-i)
                return res

        fen_dec = FenwickMax(max_v)
        fen_inc = FenwickMax(max_v)
        inc = [0] * n
        dec = [0] * n
        ans = 0
        ptr = 0
        for i in range(n):
            while ptr <= i - k:
                fen_dec.update(nums[ptr], dec[ptr])
                fen_inc.update(max_v - nums[ptr] + 1, inc[ptr])
                ptr += 1
            v = nums[i]
            best_dec_less = fen_dec.query(v - 1) if v - 1 >= 1 else 0
            inc_i = v + best_dec_less
            rev_pos = max_v - v
            best_inc_greater = fen_inc.query(rev_pos) if rev_pos >= 1 else 0
            dec_i = v + best_inc_greater
            inc[i] = inc_i
            dec[i] = dec_i
            if inc_i > ans:
                ans = inc_i
            if dec_i > ans:
                ans = dec_i
        return ans

