var maxAlternatingSum = function(nums, k) {
    const n = nums.length;
    const maxV = Math.max(...nums);

    function makeFenwick(size) {
        const tree = new Array(size + 1).fill(0);
        return {
            update(i, value) {
                while (i <= size) {
                    if (tree[i] < value) tree[i] = value;
                    i += i & (-i);
                }
            },
            query(i) {
                let res = 0;
                while (i > 0) {
                    if (tree[i] > res) res = tree[i];
                    i -= i & (-i);
                }
                return res;
            }
        };
    }

    const fenDec = makeFenwick(maxV);
    const fenInc = makeFenwick(maxV);
    const inc = new Array(n).fill(0);
    const dec = new Array(n).fill(0);
    let ans = 0;
    let ptr = 0;
    for (let i = 0; i < n; i++) {
        while (ptr <= i - k) {
            fenDec.update(nums[ptr], dec[ptr]);
            fenInc.update(maxV - nums[ptr] + 1, inc[ptr]);
            ptr++;
        }
        const v = nums[i];
        const bestDecLess = v - 1 >= 1 ? fenDec.query(v - 1) : 0;
        const incI = v + bestDecLess;
        const revPos = maxV - v;
        const bestIncGreater = revPos >= 1 ? fenInc.query(revPos) : 0;
        const decI = v + bestIncGreater;
        inc[i] = incI;
        dec[i] = decI;
        if (incI > ans) ans = incI;
        if (decI > ans) ans = decI;
    }
    return ans;
};
